# OLCVPN fix: clientID must be 'data' (olcRTC core requires non-empty DeviceID that matches the server's peer id)
$ErrorActionPreference = 'Stop'
$root = (Get-Location).Path
if (-not (Test-Path (Join-Path $root 'project.yml'))) { Write-Error 'Run from repo root (folder with project.yml).'; exit 1 }
function Write-FileB64([string]$rel,[string]$b64){
  $full = Join-Path $root $rel
  $dir = Split-Path $full
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  [System.IO.File]::WriteAllBytes($full, [System.Convert]::FromBase64String($b64))
  Write-Host ('  wrote ' + $rel)
}
Write-FileB64 'Shared/Constants.swift' ''
Write-FileB64 'App/Model/OLCUri.swift' ''
Write-FileB64 'Shared/SharedConfig.swift' ''
Write-Host ''
Write-Host 'Files written. Committing...'
git add -A
git commit -m 'Fix: clientID defaults to data (core requires non-empty DeviceID matching server)'
git push
Write-Host 'Pushed. Watch: https://github.com/lucudar/OLCVPN/actions'
